import React, { createContext, useContext, useState } from "react";

const KycContext = createContext();

export function useKyc() {
  return useContext(KycContext);
}

let nextId = 1;

export function KycProvider({ children }) {
  const [requests, setRequests] = useState([]);

  const requestKyc = (payload) => {
    const now = new Date().toISOString();
    setRequests((prev) => [
      ...prev,
      {
        id: nextId++,
        status: "pending", // 'pending' | 'approved' | 'rejected'
        createdAt: now,
        updatedAt: now,
        ...payload
      }
    ]);
  };

  const updateStatus = (id, status) => {
    setRequests((prev) =>
      prev.map((r) =>
        r.id === id ? { ...r, status, updatedAt: new Date().toISOString() } : r
      )
    );
  };

  const approveRequest = (id) => updateStatus(id, "approved");
  const rejectRequest = (id) => updateStatus(id, "rejected");

  return (
    <KycContext.Provider
      value={{ requests, requestKyc, approveRequest, rejectRequest }}
    >
      {children}
    </KycContext.Provider>
  );
}
